from flask import Flask, request, redirect, url_for, session
from authlib.integrations.flask_client import OAuth

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Client configuration
client_config = {
    'client_id': 'your_client_id',
    'client_secret': 'your_client_secret',
    'domain': 'your_domain.com',  # e.g., 'example.com' for multi-tenant support
    'redirect_uri': 'https://your_domain.com/callback',  # Use the redirect URI from client configuration
    'authorization_base_url': 'https://oauth_provider.com/authorize',
    'token_url': 'https://oauth_provider.com/token'
}

# Initialize OAuth
oauth = OAuth(app)
oauth.register(
    name='provider',
    client_id=client_config['client_id'],
    client_secret=client_config['client_secret'],
    access_token_url=client_config['token_url'],
    authorize_url=client_config['authorization_base_url'],
    redirect_uri=client_config['redirect_uri']
)

@app.route('/')
def index():
    return 'Welcome to the OAuth Client!'

@app.route('/login')
def login():
    redirect_uri = request.args.get('redirect_uri', client_config['redirect_uri'])
    
    # Validate redirect URI
    if client_config['domain'] not in redirect_uri:
        return 'Invalid redirect URI', 400
    
    session['oauth_redirect_uri'] = redirect_uri
    authorization_url, state = oauth.provider.authorize_redirect(redirect_uri=redirect_uri)
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    token = oauth.provider.authorize_access_token()
